import React, { useState, useCallback, useEffect } from 'react';
import { 
  Upload, AlertCircle, CheckCircle, Clock, Heart, Activity, 
  FileText, BarChart3, Send, X, Calendar, Menu, Image, File, Check,
  Home, ChevronLeft, Zap, Shield, TrendingUp
} from 'lucide-react';
import './App.css';

// Types
interface EcoResult {
  tem_estenose: boolean;
  gravidade: string;
  area_valvar: number | null;
  gradiente_medio: number | null;
  velocidade_maxima: number | null;
  prioridade: string;
  justificativa: string;
  indicacao_tavi: boolean;
  confianca: number;
}

interface LaudoProcessado {
  id: string;
  arquivo: string;
  formato: string;
  timestamp: string;
  analise: EcoResult;
  texto_original?: string;
  encaminhado: boolean;
  data_encaminhamento?: string;
}

interface FileUploadStatus {
  file: File;
  status: 'pending' | 'uploading' | 'success' | 'error';
  progress: number;
  result?: LaudoProcessado;
  error?: string;
}

interface Stats {
  total_laudos: number;
  indicacao_tavi: number;
  prioridade_alta: number;
  prioridade_media: number;
  prioridade_baixa: number;
  encaminhados: number;
  periodo: string;
  por_gravidade?: Record<string, number>;
}

type View = 'home' | 'upload' | 'dashboard';
type Periodo = 'dia' | 'semana' | 'mes' | 'todos' | 'custom';

const API_URL = 'http://localhost:8000';
const FORMATOS_ACEITOS = '.pdf,.txt,.png,.jpg,.jpeg,.webp,.gif,.bmp';

function App() {
  const [view, setView] = useState<View>('home');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [sidebarMobileOpen, setSidebarMobileOpen] = useState(false);
  const [internalView, setInternalView] = useState<'upload' | 'dashboard'>('upload');

  const [uploadFiles, setUploadFiles] = useState<FileUploadStatus[]>([]);
  const [dragActive, setDragActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);

  const [laudos, setLaudos] = useState<LaudoProcessado[]>([]);
  const [expandedCard, setExpandedCard] = useState<string | null>(null);

  const [stats, setStats] = useState<Stats | null>(null);
  const [periodo, setPeriodo] = useState<Periodo>('todos');
  const [customDateStart, setCustomDateStart] = useState('');
  const [customDateEnd, setCustomDateEnd] = useState('');

  const loadData = useCallback(async () => {
    try {
      setApiError(null);
      let url = `${API_URL}/estatisticas?periodo=${periodo}`;
      if (periodo === 'custom' && customDateStart && customDateEnd) {
        url = `${API_URL}/estatisticas?periodo=custom&data_inicio=${customDateStart}&data_fim=${customDateEnd}`;
      }
      const statsRes = await fetch(url);
      if (!statsRes.ok) throw new Error('Erro ao carregar estatísticas');
      const statsData = await statsRes.json();
      setStats(statsData);

      let laudosUrl = `${API_URL}/laudos?periodo=${periodo}`;
      if (periodo === 'custom' && customDateStart && customDateEnd) {
        laudosUrl = `${API_URL}/laudos?periodo=custom&data_inicio=${customDateStart}&data_fim=${customDateEnd}`;
      }
      const laudosRes = await fetch(laudosUrl);
      if (!laudosRes.ok) throw new Error('Erro ao carregar laudos');
      const laudosData = await laudosRes.json();
      setLaudos(laudosData.laudos || []);
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
    }
  }, [periodo, customDateStart, customDateEnd]);

  useEffect(() => {
    if (view !== 'home') loadData();
  }, [loadData, view]);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  }, []);

  const addFiles = (files: File[]) => {
    const newFiles: FileUploadStatus[] = files.map(file => ({
      file,
      status: 'pending',
      progress: 0
    }));
    setUploadFiles(prev => [...prev, ...newFiles]);
  };

  const removeFile = (index: number) => {
    setUploadFiles(prev => prev.filter((_, i) => i !== index));
  };

  const processFiles = async () => {
    if (uploadFiles.length === 0) return;

    setIsProcessing(true);
    setApiError(null);
    const updatedFiles = [...uploadFiles];

    for (let i = 0; i < updatedFiles.length; i++) {
      if (updatedFiles[i].status !== 'pending') continue;

      updatedFiles[i].status = 'uploading';
      updatedFiles[i].progress = 30;
      setUploadFiles([...updatedFiles]);

      try {
        const formData = new FormData();
        formData.append('file', updatedFiles[i].file);

        updatedFiles[i].progress = 60;
        setUploadFiles([...updatedFiles]);

        const response = await fetch(`${API_URL}/analisar-arquivo`, {
          method: 'POST',
          body: formData
        });

        updatedFiles[i].progress = 90;
        setUploadFiles([...updatedFiles]);

        if (!response.ok) {
          const errorData = await response.json().catch(() => ({ detail: 'Erro no servidor' }));
          throw new Error(errorData.detail || `Erro HTTP ${response.status}`);
        }

        const result = await response.json();
        updatedFiles[i].status = 'success';
        updatedFiles[i].progress = 100;
        updatedFiles[i].result = result;
        setLaudos(prev => [result, ...prev]);

      } catch (error) {
        updatedFiles[i].status = 'error';
        const errorMsg = error instanceof Error ? error.message : 'Erro desconhecido';
        updatedFiles[i].error = errorMsg;
        if (errorMsg.includes('API') || errorMsg.includes('key') || errorMsg.includes('authentication')) {
          setApiError('Erro de autenticação com a API. Verifique a ANTHROPIC_API_KEY no backend.');
        }
      }

      setUploadFiles([...updatedFiles]);
    }

    setIsProcessing(false);
    loadData();
  };

  const clearCompleted = () => {
    setUploadFiles(prev => prev.filter(f => f.status === 'pending' || f.status === 'uploading'));
  };

  const toggleEncaminhado = async (laudoId: string, encaminhado: boolean) => {
    try {
      await fetch(`${API_URL}/encaminhar`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ laudo_id: laudoId, encaminhado })
      });
      setLaudos(prev => prev.map(l => 
        l.id === laudoId ? { ...l, encaminhado, data_encaminhamento: encaminhado ? new Date().toISOString() : undefined } : l
      ));
      loadData();
    } catch (error) {
      console.error('Erro ao atualizar encaminhamento:', error);
    }
  };

  const getFileIcon = (formato: string) => {
    switch (formato) {
      case 'pdf': return <FileText className="w-4 h-4" />;
      case 'imagem': return <Image className="w-4 h-4" />;
      default: return <File className="w-4 h-4" />;
    }
  };

  const getPrioridadeColor = (prioridade: string) => {
    switch (prioridade) {
      case 'alta': return 'bg-red-500';
      case 'media': return 'bg-amber-500';
      case 'baixa': return 'bg-emerald-500';
      default: return 'bg-slate-500';
    }
  };

  const getPrioridadeBg = (prioridade: string) => {
    switch (prioridade) {
      case 'alta': return 'bg-red-50 border-red-200';
      case 'media': return 'bg-amber-50 border-amber-200';
      case 'baixa': return 'bg-emerald-50 border-emerald-200';
      default: return 'bg-slate-50 border-slate-200';
    }
  };

  // HOME / LANDING PAGE
  if (view === 'home') {
    return (
      <div className="min-h-screen bg-slate-50">
        {/* Header */}
        <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex items-center justify-between h-16">
              <img src="/logo.png" alt="CardioScreen" className="h-10 w-auto" />
              <button
                onClick={() => setView('upload')}
                className="px-4 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition-colors"
              >
                Acessar Sistema
              </button>
            </div>
          </div>
        </header>

        {/* Hero Section */}
        <section className="relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-br from-blue-900 via-blue-800 to-indigo-900"></div>
          <div className="absolute inset-0 opacity-20">
            <div className="absolute inset-0" style={{backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '40px 40px'}}></div>
          </div>

          <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 sm:py-28 lg:py-32">
            <div className="text-center">
              <div className="inline-flex items-center gap-2 px-4 py-2 bg-white/10 backdrop-blur-sm rounded-full mb-8 border border-white/20">
                <Heart className="w-5 h-5 text-red-400" />
                <span className="text-white/90 font-medium">Triagem Inteligente com IA</span>
              </div>

              <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight">
                Análise Automatizada de
                <span className="block mt-2 text-transparent bg-clip-text bg-gradient-to-r from-red-400 via-red-300 to-orange-300">
                  Laudos de Ecocardiograma
                </span>
              </h1>

              <p className="text-xl text-blue-100/80 max-w-3xl mx-auto mb-10">
                Identifique automaticamente pacientes com estenose aórtica candidatos a TAVI usando inteligência artificial avançada
              </p>

              <div className="flex flex-col sm:flex-row gap-4 justify-center">
                <button
                  onClick={() => setView('upload')}
                  className="px-8 py-4 bg-white text-blue-900 font-semibold rounded-xl hover:bg-blue-50 transition-all shadow-lg shadow-blue-900/30 flex items-center justify-center gap-2"
                >
                  <Upload className="w-5 h-5" />
                  Começar Análise
                </button>
                <button
                  onClick={() => setView('dashboard')}
                  className="px-8 py-4 bg-white/10 text-white font-semibold rounded-xl hover:bg-white/20 transition-all border border-white/30 flex items-center justify-center gap-2"
                >
                  <BarChart3 className="w-5 h-5" />
                  Ver Dashboard
                </button>
              </div>
            </div>
          </div>

          <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-slate-50 to-transparent"></div>
        </section>

        {/* Features */}
        <section className="py-20 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto">
          <div className="text-center mb-16">
            <h2 className="text-3xl font-bold text-slate-800 mb-4">Como Funciona</h2>
            <p className="text-lg text-slate-600 max-w-2xl mx-auto">
              Sistema completo para triagem automatizada de estenose aórtica
            </p>
          </div>

          <div className="grid md:grid-cols-3 gap-8">
            <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-200 hover:shadow-lg transition-shadow">
              <div className="w-14 h-14 bg-blue-100 rounded-xl flex items-center justify-center mb-6">
                <Upload className="w-7 h-7 text-blue-600" />
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-3">Upload Múltiplo</h3>
              <p className="text-slate-600">
                Carregue múltiplos laudos de uma vez. Suporta PDF, imagens e arquivos de texto.
              </p>
            </div>

            <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-200 hover:shadow-lg transition-shadow">
              <div className="w-14 h-14 bg-red-100 rounded-xl flex items-center justify-center mb-6">
                <Zap className="w-7 h-7 text-red-600" />
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-3">Análise com IA</h3>
              <p className="text-slate-600">
                Claude Haiku analisa cada laudo e identifica estenose aórtica com alta precisão.
              </p>
            </div>

            <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-200 hover:shadow-lg transition-shadow">
              <div className="w-14 h-14 bg-emerald-100 rounded-xl flex items-center justify-center mb-6">
                <TrendingUp className="w-7 h-7 text-emerald-600" />
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-3">Dashboard Completo</h3>
              <p className="text-slate-600">
                Acompanhe estatísticas, gerencie encaminhamentos e filtre por período.
              </p>
            </div>
          </div>
        </section>

        {/* Footer */}
        <footer className="bg-white border-t border-slate-200 py-8">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
            <img src="/logo.png" alt="CardioScreen" className="h-8 w-auto mx-auto mb-4 opacity-60" />
            <p className="text-sm text-slate-500">
              Powered by Claude Haiku • Anthropic AI
            </p>
          </div>
        </footer>
      </div>
    );
  }

  // MAIN APP WITH SIDEBAR
  return (
    <div className="min-h-screen bg-slate-100 flex">
      {/* Sidebar Desktop */}
      <aside className={`hidden lg:flex flex-col bg-white border-r border-slate-200 transition-all duration-300 ${sidebarOpen ? 'w-64' : 'w-20'}`}>
        <div className="p-4 border-b border-slate-100">
          <div className="flex items-center gap-3">
            <img src="/logo.png" alt="CardioScreen" className={`${sidebarOpen ? 'h-10' : 'h-8'} w-auto transition-all`} />
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button
            onClick={() => setView('home')}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-colors text-slate-600 hover:bg-slate-50"
          >
            <Home className="w-5 h-5 flex-shrink-0" />
            {sidebarOpen && <span className="font-medium">Início</span>}
          </button>

          <button
            onClick={() => setView('upload')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-colors ${
              view === 'upload' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50'
            }`}
          >
            <Upload className="w-5 h-5 flex-shrink-0" />
            {sidebarOpen && <span className="font-medium">Upload</span>}
          </button>

          <button
            onClick={() => setView('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-colors ${
              view === 'dashboard' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50'
            }`}
          >
            <BarChart3 className="w-5 h-5 flex-shrink-0" />
            {sidebarOpen && <span className="font-medium">Dashboard</span>}
          </button>
        </nav>

        <div className="p-4 border-t border-slate-100">
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="w-full flex items-center justify-center gap-2 px-4 py-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <ChevronLeft className={`w-5 h-5 transition-transform ${!sidebarOpen ? 'rotate-180' : ''}`} />
            {sidebarOpen && <span className="text-sm">Recolher</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-50 bg-white border-b border-slate-200">
        <div className="flex items-center justify-between px-4 h-16">
          <img src="/logo.png" alt="CardioScreen" className="h-8 w-auto" />
          <button
            onClick={() => setSidebarMobileOpen(!sidebarMobileOpen)}
            className="p-2 rounded-lg hover:bg-slate-100"
          >
            <Menu className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        {sidebarMobileOpen && (
          <div className="bg-white border-t border-slate-100 py-2">
            <button
              onClick={() => { setView('home'); setSidebarMobileOpen(false); }}
              className="w-full flex items-center gap-3 px-6 py-3 text-slate-600"
            >
              <Home className="w-5 h-5" />
              <span className="font-medium">Início</span>
            </button>
            <button
              onClick={() => { setView('upload'); setSidebarMobileOpen(false); }}
              className={`w-full flex items-center gap-3 px-6 py-3 ${view === 'upload' ? 'bg-blue-50 text-blue-700' : 'text-slate-600'}`}
            >
              <Upload className="w-5 h-5" />
              <span className="font-medium">Upload</span>
            </button>
            <button
              onClick={() => { setView('dashboard'); setSidebarMobileOpen(false); }}
              className={`w-full flex items-center gap-3 px-6 py-3 ${view === 'dashboard' ? 'bg-blue-50 text-blue-700' : 'text-slate-600'}`}
            >
              <BarChart3 className="w-5 h-5" />
              <span className="font-medium">Dashboard</span>
            </button>
          </div>
        )}
      </div>

      {/* Main Content */}
      <main className="flex-1 lg:pt-0 pt-16">
        <div className="max-w-6xl mx-auto p-4 sm:p-6 lg:p-8">

          {/* API Error Alert */}
          {apiError && (
            <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl flex items-start gap-3">
              <AlertCircle className="w-5 h-5 text-red-500 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-medium text-red-800">Erro de Conexão</p>
                <p className="text-sm text-red-600">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="ml-auto">
                <X className="w-5 h-5 text-red-400" />
              </button>
            </div>
          )}

          {/* UPLOAD VIEW */}
          {view === 'upload' && (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-slate-800">Upload de Laudos</h1>
              </div>

              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-6">
                  <div 
                    onDragEnter={handleDrag}
                    onDragLeave={handleDrag}
                    onDragOver={handleDrag}
                    onDrop={handleDrop}
                    className={`border-2 border-dashed rounded-xl transition-all ${
                      dragActive ? 'border-blue-500 bg-blue-50' : 'border-slate-300 hover:border-blue-400'
                    }`}
                  >
                    <input
                      type="file"
                      multiple
                      accept={FORMATOS_ACEITOS}
                      onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
                      className="hidden"
                      id="file-upload"
                    />
                    <label htmlFor="file-upload" className="cursor-pointer block p-10 text-center">
                      <div className={`inline-flex p-4 rounded-full mb-4 ${dragActive ? 'bg-blue-100' : 'bg-slate-100'}`}>
                        <Upload className={`w-10 h-10 ${dragActive ? 'text-blue-600' : 'text-slate-400'}`} />
                      </div>
                      <p className="text-lg font-medium text-slate-700">
                        {dragActive ? 'Solte os arquivos aqui' : 'Arraste arquivos ou clique para selecionar'}
                      </p>
                      <p className="text-sm text-slate-500 mt-2">PDF, imagens (PNG, JPG) e TXT</p>
                    </label>
                  </div>

                  {uploadFiles.length > 0 && (
                    <div className="mt-6 space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="font-semibold text-slate-700">
                          {uploadFiles.length} arquivo{uploadFiles.length > 1 ? 's' : ''}
                        </h3>
                        <button onClick={clearCompleted} className="text-sm text-slate-500 hover:text-slate-700">
                          Limpar concluídos
                        </button>
                      </div>

                      <div className="space-y-2 max-h-72 overflow-y-auto">
                        {uploadFiles.map((item, index) => (
                          <div 
                            key={index}
                            className={`flex items-center gap-3 p-4 rounded-lg border ${
                              item.status === 'success' ? 'bg-emerald-50 border-emerald-200' :
                              item.status === 'error' ? 'bg-red-50 border-red-200' :
                              item.status === 'uploading' ? 'bg-blue-50 border-blue-200' :
                              'bg-slate-50 border-slate-200'
                            }`}
                          >
                            <div className="flex-shrink-0">
                              {item.status === 'success' ? <CheckCircle className="w-5 h-5 text-emerald-500" /> :
                               item.status === 'error' ? <AlertCircle className="w-5 h-5 text-red-500" /> :
                               item.status === 'uploading' ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> :
                               <FileText className="w-5 h-5 text-slate-400" />}
                            </div>

                            <div className="flex-1 min-w-0">
                              <p className="font-medium text-slate-700 truncate">{item.file.name}</p>
                              {item.status === 'uploading' && (
                                <div className="mt-2 h-2 bg-slate-200 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{ width: `${item.progress}%` }} />
                                </div>
                              )}
                              {item.status === 'success' && item.result && (
                                <div className="flex items-center gap-2 mt-1">
                                  <span className={`px-2 py-0.5 rounded text-xs font-bold text-white ${getPrioridadeColor(item.result.analise.prioridade)}`}>
                                    {item.result.analise.prioridade.toUpperCase()}
                                  </span>
                                  {item.result.analise.indicacao_tavi && (
                                    <span className="px-2 py-0.5 rounded text-xs font-bold bg-red-600 text-white">TAVI</span>
                                  )}
                                </div>
                              )}
                              {item.status === 'error' && (
                                <p className="text-sm text-red-600 mt-1">{item.error}</p>
                              )}
                            </div>

                            {item.status === 'pending' && (
                              <button onClick={() => removeFile(index)} className="p-1 hover:bg-slate-200 rounded">
                                <X className="w-4 h-4 text-slate-400" />
                              </button>
                            )}
                          </div>
                        ))}
                      </div>

                      <button
                        onClick={processFiles}
                        disabled={isProcessing || uploadFiles.every(f => f.status !== 'pending')}
                        className="w-full py-3 bg-blue-600 text-white font-semibold rounded-xl hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed transition-colors flex items-center justify-center gap-2"
                      >
                        {isProcessing ? (
                          <>
                            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                            Processando com IA...
                          </>
                        ) : (
                          <>
                            <Zap className="w-5 h-5" />
                            Analisar com IA
                          </>
                        )}
                      </button>
                    </div>
                  )}
                </div>
              </div>

              {/* Results */}
              {laudos.length > 0 && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <div className="p-4 sm:p-6 border-b border-slate-100">
                    <h2 className="text-lg font-bold text-slate-800">Resultados ({laudos.length})</h2>
                  </div>

                  <div className="overflow-x-auto">
                    <table className="w-full">
                      <thead className="bg-slate-50 hidden sm:table-header-group">
                        <tr>
                          <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Arquivo</th>
                          <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Prioridade</th>
                          <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Gravidade</th>
                          <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">TAVI</th>
                          <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Ação</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                        {laudos.map((laudo) => (
                          <tr key={laudo.id} className={`${getPrioridadeBg(laudo.analise.prioridade)} hover:bg-opacity-75`}>
                            <td className="px-4 py-3">
                              <div className="flex items-center gap-2">
                                {getFileIcon(laudo.formato)}
                                <span className="font-medium text-slate-800 truncate max-w-[180px]">{laudo.arquivo}</span>
                              </div>
                            </td>
                            <td className="px-4 py-3">
                              <span className={`px-2 py-1 rounded text-xs font-bold text-white ${getPrioridadeColor(laudo.analise.prioridade)}`}>
                                {laudo.analise.prioridade.toUpperCase()}
                              </span>
                            </td>
                            <td className="px-4 py-3 capitalize text-slate-700">{laudo.analise.gravidade}</td>
                            <td className="px-4 py-3">
                              {laudo.analise.indicacao_tavi ? (
                                <span className="px-2 py-1 rounded text-xs font-bold bg-red-600 text-white">SIM</span>
                              ) : <span className="text-slate-400">-</span>}
                            </td>
                            <td className="px-4 py-3">
                              <button
                                onClick={() => toggleEncaminhado(laudo.id, !laudo.encaminhado)}
                                className={`p-2 rounded-lg transition-colors ${
                                  laudo.encaminhado ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-500'
                                }`}
                                title={laudo.encaminhado ? 'Encaminhado' : 'Marcar como encaminhado'}
                              >
                                {laudo.encaminhado ? <Check className="w-4 h-4" /> : <Send className="w-4 h-4" />}
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* DASHBOARD VIEW */}
          {view === 'dashboard' && (
            <div className="space-y-6">
              <h1 className="text-2xl font-bold text-slate-800">Dashboard</h1>

              {/* Period Filter */}
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
                <div className="flex flex-wrap items-center gap-4">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-5 h-5 text-slate-400" />
                    <span className="font-medium text-slate-700">Período:</span>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {(['dia', 'semana', 'mes', 'todos', 'custom'] as Periodo[]).map((p) => (
                      <button
                        key={p}
                        onClick={() => setPeriodo(p)}
                        className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                          periodo === p ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                        }`}
                      >
                        {p === 'dia' ? 'Hoje' : p === 'semana' ? 'Semana' : p === 'mes' ? 'Mês' : p === 'todos' ? 'Todos' : 'Custom'}
                      </button>
                    ))}
                  </div>
                  {periodo === 'custom' && (
                    <div className="flex items-center gap-2">
                      <input type="date" value={customDateStart} onChange={(e) => setCustomDateStart(e.target.value)} className="px-3 py-1.5 border border-slate-300 rounded-lg text-sm" />
                      <span className="text-slate-400">até</span>
                      <input type="date" value={customDateEnd} onChange={(e) => setCustomDateEnd(e.target.value)} className="px-3 py-1.5 border border-slate-300 rounded-lg text-sm" />
                    </div>
                  )}
                </div>
              </div>

              {/* Stats */}
              {stats && (
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                  <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5">
                    <div className="flex items-center gap-3">
                      <div className="p-3 bg-blue-100 rounded-xl">
                        <Activity className="w-6 h-6 text-blue-600" />
                      </div>
                      <div>
                        <p className="text-2xl font-bold text-slate-800">{stats.total_laudos}</p>
                        <p className="text-sm text-slate-500">Total</p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-white rounded-xl shadow-sm border border-red-200 p-5">
                    <div className="flex items-center gap-3">
                      <div className="p-3 bg-red-100 rounded-xl">
                        <Heart className="w-6 h-6 text-red-600" />
                      </div>
                      <div>
                        <p className="text-2xl font-bold text-red-600">{stats.indicacao_tavi}</p>
                        <p className="text-sm text-slate-500">TAVI</p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-white rounded-xl shadow-sm border border-emerald-200 p-5">
                    <div className="flex items-center gap-3">
                      <div className="p-3 bg-emerald-100 rounded-xl">
                        <Send className="w-6 h-6 text-emerald-600" />
                      </div>
                      <div>
                        <p className="text-2xl font-bold text-emerald-600">{stats.encaminhados}</p>
                        <p className="text-sm text-slate-500">Encaminhados</p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-white rounded-xl shadow-sm border border-amber-200 p-5">
                    <div className="flex items-center gap-3">
                      <div className="p-3 bg-amber-100 rounded-xl">
                        <Clock className="w-6 h-6 text-amber-600" />
                      </div>
                      <div>
                        <p className="text-2xl font-bold text-amber-600">{stats.total_laudos - stats.encaminhados}</p>
                        <p className="text-sm text-slate-500">Pendentes</p>
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {/* Charts */}
              {stats && (
                <div className="grid lg:grid-cols-2 gap-6">
                  <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                    <h3 className="font-bold text-slate-800 mb-4">Por Prioridade</h3>
                    <div className="space-y-4">
                      {[
                        { label: 'Alta', value: stats.prioridade_alta, color: 'bg-red-500', textColor: 'text-red-600' },
                        { label: 'Média', value: stats.prioridade_media, color: 'bg-amber-500', textColor: 'text-amber-600' },
                        { label: 'Baixa', value: stats.prioridade_baixa, color: 'bg-emerald-500', textColor: 'text-emerald-600' },
                      ].map(item => (
                        <div key={item.label}>
                          <div className="flex justify-between text-sm mb-1">
                            <span className="text-slate-600">{item.label}</span>
                            <span className={`font-medium ${item.textColor}`}>{item.value}</span>
                          </div>
                          <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
                            <div className={`h-full ${item.color} rounded-full`} style={{ width: `${stats.total_laudos ? (item.value / stats.total_laudos) * 100 : 0}%` }} />
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                    <h3 className="font-bold text-slate-800 mb-4">Por Gravidade</h3>
                    <div className="space-y-3">
                      {stats.por_gravidade && Object.entries(stats.por_gravidade).map(([gravidade, count]) => (
                        <div key={gravidade} className="flex items-center justify-between">
                          <span className="text-slate-600 capitalize">{gravidade}</span>
                          <span className="px-3 py-1 bg-slate-100 rounded-full text-sm font-medium">{count}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
